300	func readRecentSessionIndexFiles(files []string, perFile int) ([]SessionIndexEntry, error) {
301		var out []SessionIndexEntry
302		for _, file := range files {
303			data, err := os.ReadFile(file)
304			if os.IsNotExist(err) {
305				continue
306			}
307			if err != nil {
308				return nil, err
309			}
310			lines := bytes.Split(bytes.TrimSpace(data), []byte{'\n'})
311			start := 0
312			if perFile > 0 && len(lines) > perFile {
313				start = len(lines) - perFile
314			}
315			for _, line := range lines[start:] {
316				if len(bytes.TrimSpace(line)) == 0 {
317					continue
318				}
319				var entry SessionIndexEntry
320				if err := json.Unmarshal(line, &entry); err == nil {
321					out = append(out, entry)
322				}
323			}
324		}
325		return out, nil
326	}
