398	func ReindexLegacySessions(projectRoot, logDir string) (int, error) {
399		legacyPath := filepath.Join(logDir, LegacySessionsFileName)
400		readPath := legacyPath
401		if _, err := os.Stat(readPath); os.IsNotExist(err) {
402			readPath = filepath.Join(logDir, LegacySessionsRenameName)
403			if _, legacyErr := os.Stat(readPath); os.IsNotExist(legacyErr) {
404				return 0, nil
405			} else if legacyErr != nil {
406				return 0, legacyErr
407			}
408		} else if err != nil {
409			return 0, err
410		}
411	
412		existing, err := existingSessionIndexIDs(logDir)
413		if err != nil {
414			return 0, err
415		}
416		count := 0
417		err = ForEachJSONL[SessionEntry](readPath, func(entry SessionEntry) error {
418			if entry.ID == "" {
419				return nil
420			}
421			if _, ok := existing[entry.ID]; ok {
422				return nil
423			}
424			idx := SessionIndexEntryFromLegacy(projectRoot, entry)
425			if err := AppendSessionIndex(logDir, idx, entry.Timestamp.UTC()); err != nil {
426				return err
427			}
428			existing[entry.ID] = struct{}{}
429			count++
430			return nil
431		})
432		if err != nil {
433			return count, err
434		}
435		if readPath == legacyPath {
436			renamed := filepath.Join(logDir, LegacySessionsRenameName)
437			if _, err := os.Stat(renamed); os.IsNotExist(err) {
438				if err := os.Rename(legacyPath, renamed); err != nil {
439					return count, err
440				}
441			}
442		}
443		return count, nil
444	}
