615	func bodiesFromNativeLog(path string) (string, string) {
616		f, err := os.Open(path)
617		if err != nil {
618			return "", ""
619		}
620		defer f.Close()
621		var response, stderr string
622		scanner := bufio.NewScanner(f)
623		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
624		for scanner.Scan() {
625			var raw map[string]any
626			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
627				continue
628			}
629			if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
630				response = s
631			}
632			if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
633				stderr = s
634			}
635		}
636		return response, stderr
637	}
