639	func firstString(raw map[string]any, keys ...string) string {
640		for _, key := range keys {
641			if s, ok := raw[key].(string); ok && s != "" {
642				return s
643			}
644		}
645		return ""
646	}
647	
648	func firstNestedString(raw map[string]any, paths ...[]string) string {
649		for _, path := range paths {
650			cur := any(raw)
651			for _, key := range path {
652				m, ok := cur.(map[string]any)
653				if !ok {
654					cur = nil
655					break
656				}
657				cur = m[key]
658			}
659			if s, ok := cur.(string); ok && s != "" {
660				return s
661			}
662		}
663		return ""
664	}
