70	// RunViaServiceWith is the variant of RunViaService that accepts a pre-built
71	// DdxAgent so callers issuing many requests can reuse one service instance.
72	func RunViaServiceWith(ctx context.Context, svc agentlib.DdxAgent, workDir string, opts RunOptions) (*Result, error) {
73		if svc == nil {
74			return nil, fmt.Errorf("agent: nil service")
75		}
76		if ctx == nil {
77			ctx = context.Background()
78		}
79		if opts.Context != nil {
80			ctx = opts.Context
81		}
82	
83		// Resolve prompt either from inline text or PromptFile.
84		promptText := opts.Prompt
85		if opts.PromptFile != "" {
86			data, err := os.ReadFile(opts.PromptFile)
87			if err != nil {
88				return nil, fmt.Errorf("agent: read prompt file: %w", err)
89			}
90			promptText = string(data)
91		}
92		if promptText == "" {
93			return nil, fmt.Errorf("agent: prompt is required")
94		}
95	
96		wd := opts.WorkDir
97		if wd == "" {
98			wd = workDir
99		}
100		if wd == "" {
101			wd, _ = os.Getwd()
102		}
103	
104		idle := opts.Timeout
105		if idle <= 0 {
106			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
107		}
108		wall := opts.WallClock
109		if wall <= 0 {
110			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
111		}
112	
113		logDir := opts.SessionLogDir
114		if logDir == "" {
115			logDir = ResolveLogDir(workDir, "")
116		}
117	
118		harness := opts.Harness
119		if harness == "" && opts.Provider != "" {
120			// Honour --provider as a harness alias when no harness is explicit
121			// (matches Runner.resolveHarness behaviour).
122			harness = opts.Provider
123		}
124	
125		req := agentlib.ServiceExecuteRequest{
126			Prompt:          promptText,
127			Model:           opts.Model,
128			Provider:        opts.Provider,
129			Harness:         harness,
130			ModelRef:        opts.ModelRef,
131			Reasoning:       agentlib.Reasoning(opts.Effort),
132			Permissions:     opts.Permissions,
133			WorkDir:         wd,
134			Timeout:         wall,
135			IdleTimeout:     idle,
136			ProviderTimeout: DefaultProviderRequestTimeout,
137			SessionLogDir:   logDir,
138			Metadata:        opts.Correlation,
139		}
140	
141		cancelCtx, cancel := context.WithCancel(ctx)
142		defer cancel()
143	
144		start := time.Now().UTC()
145		events, err := svc.Execute(cancelCtx, req)
146		if err != nil {
147			return nil, fmt.Errorf("agent: execute: %w", err)
148		}
149	
150		final, toolCalls, routing := drainServiceEvents(events)
151		finishedAt := time.Now().UTC()
152		elapsed := finishedAt.Sub(start)
153	
154		result := &Result{
155			Harness:    harness,
156			Model:      opts.Model,
157			DurationMS: int(elapsed.Milliseconds()),
158			ToolCalls:  toolCalls,
159		}
160		if routing != nil {
161			result.Provider = routing.Provider
162			if routing.Model != "" {
163				result.Model = routing.Model
164			}
165			if routing.Harness != "" {
166				result.Harness = routing.Harness
167			}
168		}
169		if final != nil {
170			// Normalized final text from the upstream harness (agent-32e8ff5e);
171			// reviewer verdict extraction now parses this instead of raw stream
172			// frames (ddx-7bc0c8d5).
173			result.Output = final.FinalText
174			if final.Usage != nil {
175				// v0.9.1: Usage fields became *int (nullable).
176				if final.Usage.InputTokens != nil {
177					result.InputTokens = *final.Usage.InputTokens
178				}
179				if final.Usage.OutputTokens != nil {
180					result.OutputTokens = *final.Usage.OutputTokens
181				}
182				if final.Usage.TotalTokens != nil {
183					result.Tokens = *final.Usage.TotalTokens
184				}
185			}
186			if final.CostUSD > 0 {
187				result.CostUSD = final.CostUSD
188			}
189			if final.RoutingActual != nil {
190				if result.Provider == "" {
191					result.Provider = final.RoutingActual.Provider
192				}
193				if final.RoutingActual.Model != "" {
194					result.Model = final.RoutingActual.Model
195				}
196			}
197			switch final.Status {
198			case "success", "":
199				// happy path
200			case "stalled":
201				result.ExitCode = 1
202				if final.Error != "" {
203					result.Error = "stalled: " + final.Error
204				} else {
205					result.Error = "stalled"
206				}
207			case "timed_out":
208				result.ExitCode = 1
209				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
210			case "cancelled":
211				result.ExitCode = 1
212				result.Error = "cancelled"
213			default:
214				result.ExitCode = 1
215				if final.Error != "" {
216					result.Error = final.Error
217				} else {
218					result.Error = final.Status
219				}
220			}
221			if final.SessionLogPath != "" {
222				result.AgentSessionID = final.SessionLogPath
223			}
224		}
225		entry := SessionIndexEntryFromResult(workDir, opts, result, start, finishedAt)
226		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
227		return result, nil
228	}
