697			Model:      e.Model,
698			Effort:     e.Effort,
699			DurationMs: e.DurationMS,
700			StartedAt:  e.StartedAt.UTC().Format(time.RFC3339),
701		}
702	
703		// Derive status and outcome from exit code / error.
704		if e.ExitCode != 0 || e.Outcome == "failure" {
705			sess.Status = "failed"
706			outcome := "failure"
707			sess.Outcome = &outcome
