520	// formatComma formats an integer with comma separators.
521	func formatComma(n int) string {
522		s := strconv.Itoa(n)
523		if len(s) <= 3 {
524			return s
525		}
526		var b strings.Builder
527		start := len(s) % 3
528		b.WriteString(s[:start])
529		for i := start; i < len(s); i += 3 {
530			if i > 0 {
531				b.WriteByte(',')
532			}
533			b.WriteString(s[i : i+3])
534		}
535		return b.String()
536	}
