221	// parseSince converts a --since string to a time.Time cutoff.
222	func parseSince(s string) (time.Time, error) {
223		switch s {
224		case "today":
225			now := time.Now()
226			return time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location()), nil
227		case "":
228			return time.Now().AddDate(0, 0, -30), nil
229		}
230		if strings.HasSuffix(s, "d") {
231			n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
232			if err != nil {
233				return time.Time{}, fmt.Errorf("expected Nd format, got %q", s)
234			}
235			return time.Now().AddDate(0, 0, -n), nil
236		}
237		// Try ISO date
238		t, err := time.Parse("2006-01-02", s)
239		if err != nil {
240			return time.Time{}, fmt.Errorf("unrecognized format %q, want today, Nd, or YYYY-MM-DD", s)
241		}
242		return t, nil
243	}
