1181	// agentLogFormatElapsed formats a duration as a human-readable string (e.g. "5s", "3m", "2h", "1d").
1182	func agentLogFormatElapsed(d time.Duration) string {
1183		if d < 0 {
1184			d = 0
1185		}
1186		if d < time.Minute {
1187			return fmt.Sprintf("%ds", int(d.Seconds()))
1188		}
1189		if d < time.Hour {
1190			return fmt.Sprintf("%dm", int(d.Minutes()))
1191		}
1192		if d < 24*time.Hour {
1193			return fmt.Sprintf("%dh", int(d.Hours()))
1194		}
1195		return fmt.Sprintf("%dd", int(d.Hours()/24))
1196	}
